// // This module compares two 2-bit inputs and outputs a 2-bit result. If A is less than B, the output is 01; if A is greater than B, the output is 10; otherwise, it's 11.
module top_module(
    input [1:0] A,
    input [1:0] B,
    output reg [1:0] out
);always @(*) begin
        if (A > B) begin
            out = 2'b01;
        end else if (A < B) begin
            out = 2'b10;
        end else begin
            out = 2'b11;
        end
    end

endmodule
